class Solution {
    static final int MAX = 100_000;
    static boolean[] isPrime = new boolean[MAX + 1];
    static {
        java.util.Arrays.fill(isPrime, true);
        isPrime[0] = isPrime[1] = false;
        for (int i = 2; i * i <= MAX; ++i) {
            if (isPrime[i]) {
                for (int j = i * i; j <= MAX; j += i) {
                    isPrime[j] = false;
                }
            }
        }
    }

    public int[] maximumCount(int[] nums, int[][] queries) {
        int n = nums.length;
        int q = queries.length;
        int[] res = new int[q];

        int[] prefix = new int[n + 1];
        int[] suffix = new int[n + 2];

        java.util.HashSet<Integer> seenPrefix = new java.util.HashSet<>();
        java.util.HashSet<Integer> seenSuffix = new java.util.HashSet<>();

        // Build initial suffix counts
        for (int i = n - 1; i >= 0; --i) {
            suffix[i] = suffix[i + 1];
            int v = nums[i];
            if (isPrime[v] && !seenSuffix.contains(v)) {
                seenSuffix.add(v);
                suffix[i]++;
            }
        }

        for (int i = 0; i < q; ++i) {
            int idx = queries[i][0];
            int val = queries[i][1];

            // Update nums[idx] to val
            int oldVal = nums[idx];
            nums[idx] = val;

            // Recompute prefix up to idx
            seenPrefix.clear();
            for (int j = 0; j <= idx; ++j) {
                int v = nums[j];
                if (isPrime[v]) seenPrefix.add(v);
            }
            prefix[idx + 1] = seenPrefix.size();

            // Recompute suffix from idx
            seenSuffix.clear();
            for (int j = n - 1; j >= idx; --j) {
                int v = nums[j];
                suffix[j] = suffix[j + 1];
                if (isPrime[v] && !seenSuffix.contains(v)) {
                    seenSuffix.add(v);
                    suffix[j]++;
                }
            }

            // Compute max split
            int max = 0;
            for (int k = 1; k < n; ++k) {
                int left = prefix[k];
                int right = suffix[k];
                max = Math.max(max, left + right);
            }
            res[i] = max;
        }
        return res;
    }
}
